import { Autumn } from 'autumn-js';
import { randomUUID } from 'crypto';

const autumn = new Autumn({
  secretKey: process.env.AUTUMN_SECRET_KEY,
});

/**
 * Generates an AI completion with Autumn's balance locking pattern.
 *
 * Flow:
 *   1. Generate a unique lockId.
 *   2. Check customer balance and acquire a lock reserving up to maxTokens.
 *   3. If not allowed, throw an error immediately (lock was never held).
 *   4. Simulate AI work (100 ms delay, consume 75 % of maxTokens).
 *   5. On success  â†’ finalize with action:'confirm' and the actual tokensUsed.
 *   6. On failure  â†’ finalize with action:'release' to return the held balance.
 *
 * @param {string} customerId
 * @param {number} maxTokens
 * @returns {Promise<{lockId: string, tokensUsed: number, confirmed: boolean}>}
 */
export async function generateWithBudget(customerId, maxTokens) {
  // Step 1 â€“ unique lock identifier
  const lockId = `completion_${randomUUID()}`;

  // Step 2 â€“ check balance and acquire lock
  const checkResponse = await autumn.check({
    customerId,
    featureId: 'ai-tokens',
    requiredBalance: maxTokens,
    sendEvent: true,
    lock: {
      enabled: true,
      lockId,
      expiresAt: Date.now() + 60_000,
    },
  });

  // Step 3 â€“ deny early if insufficient balance
  if (!checkResponse.allowed) {
    throw new Error('Insufficient ai-tokens balance');
  }

  // Step 4 â€“ simulate AI work; wrap in try/catch for error-path finalisation
  let tokensUsed;
  try {
    await new Promise((resolve) => setTimeout(resolve, 100));
    tokensUsed = Math.floor(maxTokens * 0.75);
  } catch (workError) {
    // Step 7 â€“ release the held balance on failure
    await autumn.balances.finalize({ lockId, action: 'release' });
    throw workError;
  }

  // Step 5 â€“ confirm with the actual tokens consumed
  await autumn.balances.finalize({
    lockId,
    action: 'confirm',
    overrideValue: tokensUsed,
  });

  // Step 6 â€“ return result
  return { lockId, tokensUsed, confirmed: true };
}

